#include <iostream>
#include <string>
#include <vector>
using namespace std;

int main(int argc, const char * argv[]) {
    string pieces;
    getline(cin,pieces);
    string allpieces = pieces;
    for (auto c:pieces) allpieces+=tolower(c);

    vector<vector<string>> board(2, vector<string>(8));
    for (auto&b:board)
        for (auto&l:b)
            getline(cin, l);

    string sb="a8",se="a8";
    bool taken=false;
    for (int i=0; i<8; i++) {
        for (int j=0; j<8; j++) {
            if (board[1][i][j]!=board[0][i][j]) {
                if (allpieces.find(board[1][i][j])==string::npos) { // empty = start ?
                    if (allpieces.find(board[0][i][j])!=string::npos) { // if not noise
                        sb[1]-=i;sb[0]+=j;
                    }
                }
                else {    // target
                    se[1]-=i;se[0]+=j;
                    taken = allpieces.find(board[0][i][j])!=string::npos;
                }
            }
        }
    }
    cout <<sb<<(taken?'x':'-')<<se<<endl;
}
